head.script:
// 화면 - $Id: fi_301_04_01b.jsp,v 1.39 2010/12/29 08:13:54 오경근 Exp $
// 설명 - 자산의 폐기를 처리하는 화면
// 화면규칙
// 	1. 폐기수량에 따라 폐기취득가액,폐기장부가액,폐기전기누계액,폐기당기누계액을 자동계산한다.
// 	          폐기취득가액    = 취득가액 * (폐기수량/수량)
// 	          폐기장부가액    = 장부가액 * (폐기수량/수량)
// 	          폐기전기누계액 = 전기누계액 * (폐기수량/수량)
// 	          폐기당기누계액 = 당기누계액 * (폐기수량/수량)
// 	2. 1 의 계산된 금액은 수정할 수 없다.
// 	3. 폐기수량은 수량과 같거나 작아야 하며 정수 또는 1이하의 소수(소수점2자리)로 입력가능하다.
// 	      참고) 폐기수량이 1미만의 소수이면 자신의 이력수량은 0으로 저장한다.
// 	4. 폐기손 = 폐기장부가액


// 전역변수
scwin.login = $c.data.getMemInfo();
scwin.privAdmin = scwin.login.privAdmin;
scwin.sysAdminYn = scwin.login.sysAdminYn;
scwin.vUserHomeClsCd = scwin.login.userHomeClsCd;
scwin.vLoginCoCd = scwin.login.coCd;
scwin.vLoginCoClsCd = scwin.login.coClsCd;
scwin.isSubCompany = false;
scwin.vEmpNo = $c.data.getMemInfo("empNo");
scwin.isFirst = true;

scwin.txtCoClsCd;


scwin.onpageload = function () {

};

scwin.onUdcCompleted = async function () {

    btn_fileSave.hide("");

    const codeOptions = [
        { grpCd: "FI111", compID: "acb_evidClsCd", opt: { "range": "1" } }
    ];
    $c.data.setCommonCode(codeOptions);

    // $c.gus.cfDisableKey();

    // scwin.f_SearchHeaderCreate();			//조회데이터셋 생성
    dma_evidClsCd.set("00");

    //자산유형 조회
    $c.sbm.execute(sbm_asetPattern);

    // gr_transfer.TitleHeight = 30;
    scwin.f_FieldClear();

    scwin.f_setCompanyInfo();
}

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function (e) {

    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }

    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.f_PopUpCompanyInfo('T');

}

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_search, [ed_acqDtStDt, ed_acqDtEndDt, ica_procDt]);
    scwin.f_SetSrchDefault();
}

//-------------------------------------------------------------------------
// 조회 기본값 설정
//-------------------------------------------------------------------------
scwin.f_SetSrchDefault = function () {
    ed_acqDtStDt.setValue(WebSquare.date.getCurrentServerDate().substring(0, 6) + "01");
    ed_acqDtEndDt.setValue(WebSquare.date.getCurrentServerDate());
    //ed_procDt.text     = new Date().format("YYYYMMDD");
    ed_acqDtStDt.focus();
}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    if (!await scwin.f_RetrieveValidate()) {
        return false;
    }

    // gr_master.ColumnProp('procYn', 'HeadCheck') = "false";
    ed_rmk.setValue("");
    if (chk_lowerDeptIncluYn.getValue() == "1") {
        if (ed_srchAcctDeptCd.getValue() == "") {
            await $c.win.alert("하위부서포함여부 체크시에는 귀속부서를 입력해주세요.");
            ed_srchAcctDeptCd.focus();
            return;
        } else {
            dma_search.set("lowerDeptIncluYn", "1");
        }
    } else {
        dma_search.set("lowerDeptIncluYn", "");
    }

    dma_search.set("asetPatternCd", acb_asetPatternCd.getValue());
    dma_search.set("deprCompleteYn", acb_deprCompleteYn.getValue());
    dma_search.set("fixedAsetNo", ed_srchFixedAsetNo.getValue());
    dma_search.set("orgFixedAsetNo", ed_srchOrgFixedAsetNo.getValue());
    dma_search.set("procDt", ica_procDt.getValue());
    dma_search.set("coClsCd", scwin.txtCoClsCd);

    udc_fileUpload.getChildren()[0].scope_obj.scope.scwin.onpageload()
    $c.sbm.execute(sbm_search);
}

//-------------------------------------------------------------------------
// 처리일자 변경시 재조회 기능 - 년월만비교(월단위로 누계액을 가져오기 때문에)
//-------------------------------------------------------------------------
scwin.f_checkProcDt = async function () {

    var input_procDt = ica_procDt.getValue();
    var output_procDt = ica_procDt.getValue();

    if (ds_master.getTotalRow() > 0) {
        for (var i = 0; i < 1; i++) {
            var output_procDt = ds_master.getCellData(0, "procDt");
            //alert(output_procDt);
        }
    }

    if (input_procDt != output_procDt) {
        await $c.win.alert("이관일자가 변경되어 재조회 됩니다.");
        scwin.f_Retrieve();
    }
}

//-------------------------------------------------------------------------
// 조회 검증
//-------------------------------------------------------------------------
scwin.f_RetrieveValidate = async function () {
    /*
    if (ds_master.CountRow > 0 && ds_master.IsUpdated == true) {
        if (cfConfirmMsg(MSG_CM_CRM_005) == false)
            return;
    }
    */

    if ($c.gus.cfIsNull(ed_acqDtStDt.getValue()) && $c.gus.cfIsNull(ed_acqDtEndDt.getValue())
        && $c.gus.cfIsNull(acb_asetPatternCd.getValue())
        && $c.gus.cfIsNull(ed_srchAcctDeptCd.getValue()) && $c.gus.cfIsNull(ed_srchAcctDeptNm.getValue())
        && $c.gus.cfIsNull(ed_srchFixedAsetNo.getValue())) {
        await $c.gus.cfAlertMsg("조회조건을 하나 이상 입력해 주세요.");
        ed_acqDtStDt.focus();
        return false;
    }

    if (!await $c.gus.cfValidate([tbl_search])) {
        return false;
    }

    //취득 일자 체크
    if ($c.gus.cfIsNull(ed_acqDtStDt.getValue()) && !$c.gus.cfIsNull(ed_acqDtEndDt.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["취득일자"]);
        ed_acqDtStDt.focus();
        return false;
    }

    if (!$c.gus.cfIsNull(ed_acqDtStDt.getValue()) && $c.gus.cfIsNull(ed_acqDtEndDt.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["취득일자"]);
        ed_acqDtEndDt.focus();
        return false;
    }

    if (!$c.gus.cfIsNull(ed_acqDtStDt.getValue()) && !$c.gus.cfIsNull(ed_acqDtEndDt.getValue())) {
        // if (!$c.gus.cfValidateValue(ed_acqDtEndDt.getValue(),"minDate=" + ed_acqDtStDt.getValue())) {
        if (WebSquare.date.dateDiff(ed_acqDtStDt.getValue(), ed_acqDtEndDt.getValue()) < 0) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
            ed_acqDtStDt.focus();
            return false;
        }
    }

    return true;
}

//-------------------------------------------------------------------------
// 20121012 by kimseok
// 마감통제 목록조회  
// 회사코드/매각/이관/폐기 일자일자를 기준으로 현재 감가삼각마감정보를 가져온다. 
// 매각의 경우 되므로, 증빙일자가 따로 존재하며, 증빙일자를 기준으로 마감데이터를 조회한다. 
// 감가삼각마감정보가 존재하고, 진행상태코드가, 0:진행중이거나, 2:마감완료의 경우,
// 경고메세지 출력후 처리를 불가능하게 한다. 
//-------------------------------------------------------------------------
scwin.f_CloseControlRetrieve = async function () {

    var coCd = ed_coCd.getValue();                   // 회사코드
    var qryStdt = ica_procDt.getValue().substring(0, 6); // 증빙일자
    var wrkNo = "FI05";                         // 작업번호(FI05:감가삼각마감)

    var condition = "?coCd=" + coCd + "&qryStDt=" + qryStdt + "&wrkNo=" + wrkNo;

    sbm_closeControl.action = "/cm.bc.comnmgnt.closemgnt.RetrieveCloseControlListCMD.do" + condition;
    await $c.sbm.execute(sbm_closeControl);

    //dataSetDebug(ds_closeControl,true);
    // 감가삼각마감정보가 있으며, 
    if (ds_closeControl.getTotalRow() > 0) {
        // 매각일자에 해당하는월이 감가삼각 마감완료 되었거나, 진행중이라면, 매각처리를 불가능하게 한다. 
        // 공통코트[ZZ529:마감진행상태코드], 0:진행중,1:미마감,2:마감완료
        if (ds_closeControl.getCellData(0, "closePrgsStsCd") == "0") {
            await $c.win.alert("[" + qryStdt + "] 월에 감가삼각마감이 진행중입니다.\n이관처리가 불가능합니다. 재경팀의 문의하세요.");
            return false;
        }
        if (ds_closeControl.getCellData(0, "closePrgsStsCd") == "2") {
            await $c.win.alert("[" + qryStdt + "] 월에 감가삼각마감이 마감완료되었습니다.\n이관처리가 불가능합니다. 재경팀의 문의하세요.");
            return false;
        }
        else {
            return true;
        }
    }
    else {
        return true;
    }
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_SaveProc = async function () {
    ds_fileUploadGDS.removeAll();
    var evidClsCd = acb_evidClsCd.getValue();
    let fileList = udc_fileUpload.getData();

    if (fileList.length != 0) {
        if (evidClsCd == "" || evidClsCd == "00") {
            await $c.win.alert("증빙파일구분을 선택하세요");
            udc_fileUpload.getChildren()[0].scope_obj.scope.scwin.onpageload()
            return;
        } else {

            await udc_fileUpload.startFileUpload();
        }
    }

    if (ds_master.getModifiedIndex().length <= 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["폐기자산"]);
        udc_fileUpload.getChildren()[0].scope_obj.scope.scwin.onpageload()
        return;
    } else {

        // 처리일자 입력 validation
        if (!await $c.gus.cfValidate([ica_procDt])) {
            udc_fileUpload.getChildren()[0].scope_obj.scope.scwin.onpageload()
            return;
        }
        // 자산 입력 validation
        if (!await scwin.f_ValidateAset()) {
            udc_fileUpload.getChildren()[0].scope_obj.scope.scwin.onpageload()
            return;
        }
        //증빙 입력 validation
        if (!await $c.gus.cfValidate([tbl_evidence])) {
            udc_fileUpload.getChildren()[0].scope_obj.scope.scwin.onpageload()
            return;
        }

        // 마감정보가 마감완료거나 마감중이라면, 진행하지 않는다. 
        if (!await scwin.f_CloseControlRetrieve()) {
            udc_fileUpload.getChildren()[0].scope_obj.scope.scwin.onpageload()
            return;
        }

        // 비고에 ','이 있으면 진행하지 않는다. 
        if (!await scwin.f_checkComma()) {
            udc_fileUpload.getChildren()[0].scope_obj.scope.scwin.onpageload()
            return;
        }

        if (await $c.win.confirm(MSG_CM_CRM_001)) {
            for (var i = 0; i < ds_master.getTotalRow(); i++) {
                if (ds_master.getCellData(i, "procYn") == 1 || ds_master.getRowStatus(i) == "U") {
                    ds_master.setCellData(i, "procDt", ica_procDt.getValue());
                    //ds_master.NameString(i,"rmk") = txt_rmk.value;
                }
            }

            // tr_master.Parameters = "disuseDt=" + ed_procDt.text
            //                         + ",rmk=" + txt_rmk.value.trim();
            // tr_master.post();

            dma_disuseDt.set("disuseDt", ica_procDt.getValue());
            dma_rmk.set("rmk", ed_rmk.getValue());

            $c.sbm.execute(sbm_master);
        } else {
            udc_fileUpload.getChildren()[0].scope_obj.scope.scwin.onpageload()
        }
    }
}

//-------------------------------------------------------------------------
// 자산증빙 파일업로드 실행하고 저장처리
//-------------------------------------------------------------------------
scwin.f_Save = function () {
    // var formObj = document.frm;
    // todo
    // $c.gus.cfUploadFile(formObj, fileUploadGDS, "uploadComplete");
    scwin.uploadComplete();
}

scwin.uploadComplete = function () {
    scwin.f_SaveProc();
}

//-------------------------------------------------------------------------
// 자산입력 validation
//-------------------------------------------------------------------------
scwin.f_ValidateAset = async function () {
    for (var i = 0; i < ds_master.getTotalRow(); i++) {
        if (ds_master.getCellData(i, "procYn") == 1 || ds_master.getRowStatus(i) == "U") {
            // if(ds_master.getCellData(i, "numCheck") != "1"){
            if (ds_master.getCellData(i, "procQty") <= 0) {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["폐기수량"]);
                // gr_master.SetColumn("procQty");
                return false;
            }
            // }

            if (ds_master.getCellData(i, "procQty") > ds_master.getCellData(i, "qty")) {
                await $c.gus.cfAlertMsg("폐기수량이 수량을 초과하였습니다.");
                // gr_master.SetColumn("procQty");
                return false;
            }

            /*if (ds_master.NameValue(i,"acqDt") > ed_procDt.text) {
                cfAlertMsg("자산번호 " + ds_master.NameString(i,"fixedAsetNo") + " 의 폐기일자가 취득일자 이전입니다.");
                gr_master.SetColumn("fixedAsetNo");
                return false;
            }*/
            if (ds_master.getCellData(i, "procRate") == "100") {
                if (ds_master.getCellData(i, "procQty") != ds_master.getCellData(i, "qty")) {
                    await $c.gus.cfAlertMsg("비율이 100(%)인경우 수량과 폐기수량은 일치해야합니다.");
                    // gr_master.SetColumn("procQty");
                    return false;
                }
            }
        }
    }
    return true
}

//-------------------------------------------------------------------------
// 조회 귀속부서코드 팝업
//-------------------------------------------------------------------------
scwin.f_srchDeptPopUp = function (flag) {
    var param = "," + ed_coCd.getValue() + "," + scwin.txtCoClsCd;

    var rtnList = udc_srchAcctDeptCd.cfCommonPopUp(scwin.udc_srchAcctDeptCd_callBack, ed_srchAcctDeptCd.getValue(), ""
        , flag, null, null, null, null
        , param, "410", null, null, null);
}

scwin.udc_srchAcctDeptCd_callBack = function (rtnList) {

    if (rtnList != null) {
        if (rtnList[0] != "N/A") {
            ed_srchAcctDeptCd.setValue(rtnList[0]);
            ed_srchAcctDeptCd.options.hidVal = rtnList[0];
            ed_srchAcctDeptNm.setValue(rtnList[1]);
        }
    } else {
        ed_srchAcctDeptCd.setValue("");
        ed_srchAcctDeptCd.options.hidVal = "";
        ed_srchAcctDeptNm.setValue("");
    }
}

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = function (pWinCloseTF) {
    scwin.pWinClose = pWinCloseTF;
    var rtnList = udc_companyInfo.cfCommonPopUp(scwin.udc_coCd_callBackFunc
        , ed_coCd.getValue(), ed_coNm.getValue()
        , pWinCloseTF, null, null, null, null
        , null, null, null, null, null);
}

scwin.udc_coCd_callBackFunc = function (rtnList) {
    // SET	 
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_coCd.setValue(rtnList[0]);	// 코드
        ed_coNm.setValue(rtnList[5]); // 회사명 
        ed_coCd.options.hidVal = rtnList[0];  // 히든값
        scwin.txtCoClsCd = rtnList[1];	// 회사구분  

        $c.gus.cfInitObjects([ed_srchAcctDeptCd, ed_srchAcctDeptNm]); // 조회조건 - 귀속부서 
    } else {
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        ed_coCd.options.hidVal = "";
        scwin.txtCoClsCd = "";
    }

    if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {  	// 자회사 회계 시스템 
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }

    if (scwin.isFirst == true) {

        if ('T' == scwin.privAdmin || !scwin.isSubCompany) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
            $c.gus.cfEnableObjects([ed_coCd, ed_coNm, btn_company]);
        }
        else {
            $c.gus.cfDisableObjects([ed_coCd, ed_coNm, btn_company]);
        }

        scwin.isFirst = false;
    }
}

// 비고에 ',' 체크
scwin.f_checkComma = async function () {
    var chk_rmk = ed_rmk.getValue();
    var chkstr = ",";
    var checkYn = "Y";

    for (var i = 0; i < chk_rmk.length; i++) {
        if (chkstr.indexOf(chk_rmk.substring(i, i + 1)) == -1) {
            checkYn = "Y";
        } else {
            await $c.win.alert("비고에는 특수문자 , 입력이 불가능합니다.");
            checkYn = "N";
            return
        }
    }

    if (checkYn == "Y") {
        return true;
    } else {
        return false;
    }
}

//-------------------------------------------------------------------------
// 엑셀 파일 다운로드
//-------------------------------------------------------------------------
scwin.f_Excel = async function () {

    if (await $c.win.confirm("Excel로 다운로드 하시겠습니까?")) {

        var options = {
            fileName: "자산폐기.xls",
            sheetName: "자산폐기"
        }
        $c.data.downloadGridViewExcel(gr_master, options);
    }


}

scwin.udc_companyInfo_onclickEvent = function (e) {
    scwin.f_PopUpCompanyInfo('F');
};

scwin.udc_companyInfo_onblurCodeEvent = function (e) {
    ed_coNm.setValue("");
    scwin.f_PopUpCompanyInfo('T');
};

scwin.udc_srchAcctDeptCd_onclickEvent = function (e) {
    scwin.f_srchDeptPopUp("F");
};

scwin.udc_srchAcctDeptCd_onblurCodeEvent = function (e) {
    scwin.f_srchDeptPopUp("T");
};

scwin.sbm_master_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        //cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
        if (ds_slipNo.getCellData(0, "slipNo") != "") {
            $c.gus.cfShowSlipInfo(ds_slipNo.getCellData(0, "slipNo"));
        }
        ed_rmk.setValue("");
        dma_evidClsCd.set("evidClsCd", "00");
        scwin.f_Retrieve();
        // document.location.reload();
    } else {
        udc_fileUpload.getChildren()[0].scope_obj.scope.scwin.onpageload()
    }
};

scwin.sbm_search_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {

        var rowCnt = ds_master.getTotalRow();
        ed_totalRow.setValue(rowCnt);
        if (rowCnt == 0) {

            await $c.gus.cfAlertMsg(MSG_CM_WRN_002);

            $c.gus.cfDisableObjects(tbl_evidence);
        } else {
            $c.gus.cfEnableObjects(tbl_evidence);
        }

        dma_evidClsCd.set("evidClsCd", "00");
    }
};

scwin.ds_master_onrowpositionchange = function (info) {

    var row = info.rowIndex;

    if (ds_master.getCellData(row, "procYn") == 1) {
        if (ds_master.getCellData(row, "qty") == 1) {
            gr_master.setReadOnly("cell", row, "procQty", false);
            gr_master.setReadOnly("cell", row, "procRate", false);
        } else {
            gr_master.setReadOnly("cell", row, "procQty", false);
            gr_master.setReadOnly("cell", row, "procRate", false);
        }
        gr_master.setReadOnly("cell", row, "procAmt", false);
        gr_master.setReadOnly("cell", row, "reappraiseAmt", false);
        gr_master.setReadOnly("cell", row, "procArea", false);
    } else {
        gr_master.setReadOnly("cell", row, "procQty", true);
        gr_master.setReadOnly("cell", row, "procAmt", true);
        gr_master.setReadOnly("cell", row, "procRate", true);
        gr_master.setReadOnly("cell", row, "reappraiseAmt", true);
        gr_master.setReadOnly("cell", row, "procArea", true);
    }
};

scwin.ds_master_oncelldatachange = async function (info) {
    var colid = info.colID;
    var row = info.rowIndex;

    if (colid == "procYn" && ds_master.getCellData(row, "procYn") == 0) {
        ds_master.setCellData(row, "procQty", 0);
        ds_master.setCellData(row, "procAmt", 0);
        ds_master.setCellData(row, "procAcqAmt", 0);
        ds_master.setCellData(row, "procRate", 0);
        ds_master.setCellData(row, "procBefYyProvAmt", 0);
        ds_master.setCellData(row, "procThisYyProvAmt", 0);
        ds_master.setCellData(row, "procBookAmt", 0);
        ds_master.setCellData(row, "procDifferAmt", 0);
        return;
    }
    if (colid == "procYn" && ds_master.getCellData(row, "procYn") == "1" && ds_master.getCellData(row, "lentYn") == "1") {
        ds_master.setCellData(row, "procYn", 0);
        await $c.gus.cfAlertMsg("임대중인  자산은 처리할 수 없습니다.");
        return;
    }
    if ((ds_master.getCellData(row, "asetPatternNm") == "토지") || (ds_master.getCellData(row, "asetPatternNm") == "건물")) {

        if (colid == "procArea") {

            // asis에서는 수정시 procQty에 0이 아닌값 세팅함. validationCheck위해 처리  
            // var chechNum = Math.floor(Number(ds_master.getCellData(row, "procArea")) / Number(ds_master.getCellData(row, "area")) * 10000)/100; 
            // if(chechNum == 0){
            //     ds_master.setCellData(row, "numCheck", 1);
            // }
            // ds_master.setCellData(row, "procRate", Math.floor(Number(ds_master.getCellData(row, "procArea")) / Number(ds_master.getCellData(row, "area")) * 10000)/100);

            ds_master.setCellData(row, "procRate", (ds_master.getCellData(row, "procArea") / ds_master.getCellData(row, "area")) * 100);
            // ds_master.setCellData(row, "procRate", 0.001520843155445379);
            var procRate = Number(ds_master.getCellData(row, "procRate")) / 100;
            ds_master.setCellData(row, "procQty", Number(ds_master.getCellData(row, "qty")) * procRate);
        }
    } else {
        if (colid == "procQty") {
            ds_master.setCellData(row, "procRate", Math.floor(Number(ds_master.getCellData(row, "procQty")) / Number(ds_master.getCellData(row, "qty")) * 10000) / 100);
            var procRate = Number(ds_master.getCellData(row, "procRate")) / 100;
        }

    }

    //수량이 1개인 자산을 부분처리할경우 비율 입력시 수량 소숫점 자동 계산 (부분처리를 위함)
    if (colid == "procRate" && ds_master.getCellData(row, "qty") == 1) {

        const factor = Math.pow(10, 3);
        var num = (Number(ds_master.getCellData(row, "procRate")) * Number(ds_master.getCellData(row, "qty"))) / 100
        var formatNum = Math.floor(num * factor) / factor;

        ds_master.setCellData(row, "procQty", formatNum);

        // ds_master.setCellData(row, "procQty", (Number(ds_master.getCellData(row, "procRate")) * Number(ds_master.getCellData(row, "qty"))) / 100);
        // var procQty = ds_master.getCellData(row, "procQty");
    }



    if (colid == "procRate") {

        var procRate = Number(ds_master.getCellData(row, "procRate") / 100);

        //ds_master.NameValue(row,"procRate") =  (ds_master.NameValue(row, "procQty") / ds_master.NameValue(row, "qty") )   * 100 ;

        ds_master.setCellData(row, "procAcqAmt", Math.round(Number(ds_master.getCellData(row, "acqAmt")) * (procRate)));
        ds_master.setCellData(row, "procBefYyProvAmt", Math.round(Number(ds_master.getCellData(row, "befYyProvAmt")) * (procRate)));
        ds_master.setCellData(row, "procThisYyProvAmt", Math.round(Number(ds_master.getCellData(row, "thisYyProvAmt")) * (procRate)));
        ds_master.setCellData(row, "procBookAmt", Number(ds_master.getCellData(row, "procAcqAmt"))
            - (Number(ds_master.getCellData(row, "procBefYyProvAmt")) + Number(ds_master.getCellData(row, "procThisYyProvAmt"))));
        ds_master.setCellData(row, "procDifferAmt", ds_master.getCellData(row, "procBookAmt"));
    }
};

