scwin.gr_master_oncellclick = function (row, columnIndex, colid) {

    if ((ds_master.getCellData(row, "asetPatternNm") == "토지") || (ds_master.getCellData(row, "asetPatternNm") == "건물")) {

        if (colid == "procQty" || colid == "procRate") {

            gr_master.setReadOnly("cell", row, colid, true);
        }

        if (colid == "procAmt" || colid == "procArea" || colid == "reappraiseAmt") {

            if (ds_master.getCellData(row, "procYn") == 1) { // CHECK True 

                if (ds_master.getCellData(row, "qty") == 1) {

                    gr_master.setReadOnly("cell", row, colid, false);
                } else {
                    gr_master.setReadOnly("cell", row, colid, false);
                }
            } else {
                gr_master.setReadOnly("cell", row, colid, true);
                ds_master.setCellData(row, "procQty", 0);
                ds_master.setCellData(row, "procAmt", 0);
                ds_master.setCellData(row, "procRate", 0);
                ds_master.setCellData(row, "procArea", 0);
            }
        }
    } else {    //토지,건물 외


        if (colid == "procArea") {   //면적입력불 
            gr_master.setReadOnly("cell", row, colid, true);
        }

        if (colid == "procQty" || colid == "procAmt" || colid == "procRate" || colid == "reappraiseAmt") {

            if (ds_master.getCellData(row, "procYn") == 1) { // CHECK True 

                if (ds_master.getCellData(row, "qty") == 1) {
                    gr_master.setReadOnly("cell", row, colid, false);
                } else {
                    gr_master.setReadOnly("cell", row, colid, false);
                }
            } else {
                gr_master.setReadOnly("cell", row, colid, true);
                ds_master.setCellData(row, "procQty", 0)
                ds_master.setCellData(row, "procAmt", 0)
                ds_master.setCellData(row, "procRate", 0)
                ds_master.setCellData(row, "procArea", 0)
            }
        }
    }
};

scwin.gr_master_onafteredit = async function (row, columnIndex, value) {

    var colid = gr_master.getColumnID(columnIndex)

    if (colid == "procQty") {
        if (ds_master.getCellData(row, colid) > ds_master.getCellData(row, "qty")) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_014, ["폐기수량", "수량"]);
        }
    }
};

scwin.gr_master_onheaderclick = function (colid) {
    if (colid == "checkHeader") {
        var bCheck = gr_master.getHeaderValue("checkHeader");
        for (var i = 0; i < ds_master.getTotalRow(); i++) {
            if (ds_master.getCellData(i, "lentYn") != "1") {
                ds_master.setCellData(i, "procYn", (bCheck) ? 1 : 0);
            }
            if (ds_master.getCellData(i, "procYn") == "1") {
                if ((ds_master.getCellData(i, "asetPatternNm") == "토지") || (ds_master.getCellData(i, "asetPatternNm") == "건물")) {
                    ds_master.setCellData(i, "procArea", ds_master.getCellData(i, "area"));     //면적 -> 폐기면적 		
                } else {
                    ds_master.setCellData(i, "procQty", ds_master.getCellData(i, "qty"));  	  //수량 -> 폐기수량 			
                }
            } else {
                if ((ds_master.getCellData(i, "asetPatternNm") == "토지") || (ds_master.getCellData(i, "asetPatternNm") == "건물")) {
                    ds_master.setCellData(i, "procArea", 0);
                } else {
                    ds_master.setCellData(i, "procQty", 0);
                }
            }
        }
    }
};

